class HomeScreen extends StatefulWidget {
  const HomeScreen({Key? key}) : super(key: key);

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  final _authService = AuthenticationService();
  bool _isBiometricEnabled = false;

  @override
  void initState() {
    super.initState();
    _checkBiometricStatus();
  }

  Future<void> _checkBiometricStatus() async {
    final isEnabled = await _authService.isBiometricEnabled();
    setState(() {
      _isBiometricEnabled = isEnabled;
    });
  }

  Future<void> _logout() async {
    await _authService.logout();
    _navigateToLogin();
  }

  Future<void> _toggleBiometric() async {
    if (_isBiometricEnabled) {
      await _authService.disableBiometric();
      setState(() {
        _isBiometricEnabled = false;
      });
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Biometric authentication disabled')),
      );
    } else {
      final isAvailable = await _authService.isBiometricAvailable();
      if (isAvailable) {
        final didAuthenticate = await _authService.authenticateWithBiometrics();
        if (didAuthenticate) {
          setState(() {
            _isBiometricEnabled = true;
          });
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Biometric authentication enabled')),
          );
        }
      } else {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Biometric authentication not available')),
        );
      }
    }
  }

  void _navigateToLogin() {
    Navigator.of(context).pushAndRemoveUntil(
      MaterialPageRoute(builder: (context) => const LoginScreen()),
      (route) => false,
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        actions: [
          IconButton(
            icon: const Icon(Icons.logout),
            onPressed: _logout,
          ),
        ],
      ),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(24.0),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              const Icon(
                Icons.check_circle_outline,
                size: 100,
                color: Colors.green,
              ),
              const SizedBox(height: 24),
              const Text(
                'Welcome!',
                style: TextStyle(
                  fontSize: 32,
                  fontWeight: FontWeight.bold,
                ),
              ),
              const SizedBox(height: 16),
              const Text(
                'You are securely authenticated',
                style: TextStyle(fontSize: 16),
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 48),
              Card(
                child: ListTile(
                  leading: Icon(
                    _isBiometricEnabled ? Icons.fingerprint : Icons.fingerprint_outlined,
                    color: _isBiometricEnabled ? Colors.green : Colors.grey,
                  ),
                  title: const Text('Biometric Authentication'),
                  subtitle: Text(_isBiometricEnabled ? 'Enabled' : 'Disabled'),
                  trailing: Switch(
                    value: _isBiometricEnabled,
                    onChanged: (value) => _toggleBiometric(),
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}